const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');

const bigquery = new BigQuery();

functions.http('processLargeDataset', async (req, res) => {
  const projectId = process.env.GOOGLE_CLOUD_PROJECT || process.env.GCLOUD_PROJECT;
  const datasetId = req.query.datasetId || req.body?.datasetId;
  const tableId = req.query.tableId || req.body?.tableId;
  const aggregationSql = req.query.sql || req.body?.sql;

  if (!datasetId || !tableId) {
    res.status(400).json({
      error: 'Missing required parameters: datasetId and tableId'
    });
    return;
  }

  try {
    const query = aggregationSql || `
      SELECT
        COUNT(*) AS row_count
      FROM \`${projectId}.${datasetId}.${tableId}\`
    `;

    const options = {
      query,
      location: req.query.location || req.body?.location || 'US',
      useLegacySql: false,
      maximumBytesBilled: req.query.maximumBytesBilled || req.body?.maximumBytesBilled,
    };

    const [job] = await bigquery.createQueryJob(options);
    const [rows] = await job.getQueryResults({ maxResults: 10000 });

    res.status(200).json({
      success: true,
      jobId: job.id,
      rows
    });
  } catch (error) {
    console.error('BigQuery processing failed:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});